mapper.select:
SELECT il.id, il.external_id, il.item_id, i.name AS item_name,
       il.lot_number, il.expiration_date, il.created_at
FROM item_lots il
JOIN items i ON il.item_id = i.id
WHERE il.item_id = #{itemId}
  AND il.lot_number = #{lotNumber}

SELECT il.id, il.external_id, il.item_id, i.name AS item_name,
       il.lot_number, il.expiration_date, il.created_at
FROM item_lots il
JOIN items i ON il.item_id = i.id
WHERE il.external_id = #{externalId}
  AND i.user_id = #{userId}
